{
  "resolution_strategies": [
    {
      "resolution_strategy_id": "RS1_insert_consent_before_request",
      "change_operations": [
        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "Request personal data",
            "new_activity_label": "obtain data processing consent"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "obtain data processing consent",
            "new_resource": "data controller"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The missing activity obtain data processing consent is inserted directly before Request personal data, satisfying the precedence requirement. The activity is also assigned to the data controller, satisfying the executed_by requirement."
        },
        "resolution_context_consistency": {
          "value": "high",
          "reason": "Obtaining data processing consent immediately before requesting personal data is contextually appropriate and directly addresses the compliance issue without changing unrelated behavior."
        },
        "change_cost": {
          "value": "low",
          "reason": "Only one activity is added and one resource assignment is specified. No existing activities or control-flow structures need to be reorganized."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The strategy preserves the existing sequence, parallel block, and exclusive branches. It only extends the initial sequence with a required compliance activity."
        },
        "change_location": {
          "value": "early",
          "reason": "The change is applied at the beginning of the process, immediately before Request personal data."
        }
      }
    },
    {
      "resolution_strategy_id": "RS2_repurpose_existing_permission_activity",
      "change_operations": [
        {
          "operation": "rename",
          "parameters": {
            "target_activity_label": "Ask for permission",
            "new_activity_label": "obtain data processing consent"
          }
        },
        {
          "operation": "move_before",
          "parameters": {
            "source_activity_label": "obtain data processing consent",
            "target_activity_label": "Request personal data"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "obtain data processing consent",
            "new_resource": "data controller"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The existing permission-related activity is transformed into obtain data processing consent, moved before Request personal data, and assigned to the data controller. This satisfies both the precedence and resource requirements."
        },
        "resolution_context_consistency": {
          "value": "medium",
          "reason": "The existing Ask for permission activity is semantically related to consent, but moving it out of the later parallel branch may affect the original purpose of that branch."
        },
        "change_cost": {
          "value": "medium",
          "reason": "The strategy reuses an existing activity but requires renaming, relocating it across the process structure, and modifying its resource."
        },
        "structural_quality_impact": {
          "value": "medium",
          "reason": "Moving an activity out of the parallel branch changes the internal structure of that branch. The process remains structured, but the original parallel behavior is modified."
        },
        "change_location": {
          "value": "early",
          "reason": "The final compliance-relevant activity is placed before the first activity of the process."
        }
      }
    },
    {
      "resolution_strategy_id": "RS3_insert_consent_and_remove_late_permission",
      "change_operations": [
        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "Request personal data",
            "new_activity_label": "obtain data processing consent"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "obtain data processing consent",
            "new_resource": "data controller"
          }
        },
        {
          "operation": "delete",
          "parameters": {
            "target_activity_label": "Ask for permission"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The required consent activity is added before Request personal data and assigned to the required resource. Removing the later Ask for permission activity avoids a potentially redundant permission step."
        },
        "resolution_context_consistency": {
          "value": "medium",
          "reason": "The inserted consent step is consistent with the requirement, but deleting Ask for permission assumes that the new consent activity fully replaces its original business purpose."
        },
        "change_cost": {
          "value": "medium",
          "reason": "The strategy adds one activity, modifies its resource, and removes an existing activity."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The main process structure remains intact. The parallel branch containing Store Data and Ask for permission is simplified by removing one activity."
        },
        "change_location": {
          "value": "early",
          "reason": "The main compliance repair occurs at the start of the process, before Request personal data."
        }
      }
    },
    {
      "resolution_strategy_id": "RS4_partial_insert_consent_after_request",
      "change_operations": [
        {
          "operation": "insert_after",
          "parameters": {
            "target_activity_label": "Request personal data",
            "new_activity_label": "obtain data processing consent"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "obtain data processing consent",
            "new_resource": "data controller"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "partial",
          "reason": "The missing consent activity is introduced and assigned to the data controller, but it occurs after Request personal data. Therefore, the executed_by requirement is satisfied, but the precedence requirement remains violated."
        },
        "resolution_context_consistency": {
          "value": "low",
          "reason": "Obtaining consent after personal data has already been requested is weaker from a compliance perspective and does not match the stated precedence requirement."
        },
        "change_cost": {
          "value": "low",
          "reason": "Only one insertion and one resource modification are required."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The process structure is only minimally extended and no existing control-flow structures are changed."
        },
        "change_location": {
          "value": "early",
          "reason": "The inserted activity is placed near the start of the process, immediately after Request personal data."
        }
      }
    }
  ],
  "best_resolution_strategy_id": "RS1_insert_consent_before_request",
  "best_resolution_reason": "RS1 is the recommended strategy because it fully restores compliance with minimal and localized changes. It inserts the missing consent activity exactly where required, before Request personal data, and assigns it to the data controller. It does not disturb existing branches, parallelism, or later process behavior."
}
